            "constraints": {}
          }
        ]
      },
      "notes": "Valid challenge ID should return all phases."
    },
    {
      "name": "get_phases_invalid_challenge_id",
      "input": {
        "challengeId": "99999"
      },
      "output": {
        "error": "Challenge not found"
      },
      "notes": "Invalid challenge ID should return an error."
    },
    {
      "name": "get_phases_no_phases",
      "input": {
        "challengeId": "67890"
      },
      "output": {
        "phases": []
      },
      "notes": "Challenge with no phases should return an empty array."
    },
    {
      "name": "get_phases_edge_case_empty_id",
      "input": {
        "challengeId": ""
      },
      "output": {
        "error": "Invalid challenge ID"
      },
      "notes": "Empty challenge ID should return an error."
    },
    {
      "name": "get_phases_edge_case_non_numeric_id",
      "input": {
        "challengeId": "abcde"
      },
      "output": {
        "error": "Invalid challenge ID format"
      },
      "notes": "Non-numeric challenge ID should return an error."
    },
    {
      "name": "get_phases_with_constraints",
      "input": {
        "challengeId": "54321"
      },
      "output": {
        "phases": [
          {
            "id": "1",
            "name": "Submission Phase",
            "startDate": "2023-10-01T00:00:00Z",
            "endDate": "2023-10-10T00:00:00Z",
            "constraints": {
              "maxSubmissions": 5
            }
          }
        ]
      },
      "notes": "Challenge with phases that have constraints should return those constraints."
    },
    {
      "name": "get_phase_valid_challenge_id",
      "input": {
        "challengeId": "12345",
        "phaseId": "1"
      },
      "output": {
        "id": "1",
        "name": "Submission Phase",
        "startDate": "2023-10-01T00:00:00Z",
        "endDate": "2023-10-10T00:00:00Z",
        "constraints": {}
      },
      "notes": "Valid challenge and phase ID should return the specific phase."
    },
    {
      "name": "get_phase_invalid_phase_id",
      "input": {
        "challengeId": "12345",
        "phaseId": "999"
      },
      "output": {
        "error": "Phase not found"
      },
      "notes": "Invalid phase ID should return an error."
    }
  ],
